import { Result } from "antd"
import { useContext, useEffect, useLayoutEffect, useState } from "react"
import { useSelector } from "react-redux"
import { NavLink, Navigate, Outlet, useLocation } from "react-router-dom"
import MainLayout from "src/components/Layout"
import ButtonCustom from "src/components/MyButton/Button"
import { StoreContext } from "src/contexts"
import { hasPermission } from "src/lib/utils"
import { MenuItemAdmin } from "src/router/MenuItem"
import ROUTER from "src/router/ROUTER"

function AdminRoutes() {
  const { routerBeforeStore } = useContext(StoreContext)
  const { setRouterBeforeLogin } = routerBeforeStore
  const { listTabs, userInfo } = useSelector(state => state?.appGlobal)
  const [menuAdmin, setMenuAdmin] = useState([])
  const { loginStore } = useContext(StoreContext)
  const { isLoginContext } = loginStore
  const location = useLocation()
  const setShowListMenu = list =>
    list?.length
      ? list
          ?.filter(x => hasPermission(x?.TabID, [...listTabs]))
          .map(i => ({
            ...i,
            children: setShowListMenu(i?.children),
          }))
      : undefined
  useEffect(() => {
    if (!isLoginContext)
      setRouterBeforeLogin(`${location.pathname}${location?.search}`)
  }, [isLoginContext])
  useLayoutEffect(() => {
    if (isLoginContext) {
      const menu = setShowListMenu(MenuItemAdmin())
      setMenuAdmin(menu)
    }
  }, [userInfo, listTabs])
  return isLoginContext ? (
    <>
      {menuAdmin?.length > 0 ? (
        <MainLayout type="isAdmin">
          <Outlet />
        </MainLayout>
      ) : (
        <Result
          status="403"
          title="403 Erorr Permission"
          subTitle="Xin lỗi, Bạn không có quyền truy cập trang web."
          extra={
            <NavLink to={ROUTER.DEFAULT}>
              <div style={{ display: "flex", justifyContent: "center" }}>
                <ButtonCustom className="btn-hover-shadow">
                  Quay lại trang chủ
                </ButtonCustom>
              </div>
            </NavLink>
          }
        />
      )}
    </>
  ) : (
    <Navigate to={ROUTER.DANG_NHAP} />
  )
}

export default AdminRoutes
